sql:
SELECT COUNT(*) 
FROM sensor_stations 
WHERE status = 'active';

SELECT location
FROM sensor_stations
WHERE status = 'active';

SELECT station_id, location, sensor_type, last_calibration_date
FROM sensor_stations
ORDER BY station_id;

